# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import time
from machine import Pin, ADC
from umqtt.simple import MQTTClient

# Define the client ID and broker IP
client_id = b'micropython_sensor'
broker_ip = '192.168.1.100'

# Set up the ADC for temperature sensor (e.g., DS18B20)
temp_sensor = ADC(4)  # Assuming connected to GPIO 4

def read_temperature():
    reading = temp_sensor.read()
    # Convert reading to temperature
    temperature = reading * 3.3 / 4095 * 100  # Example conversion
    return temperature

# Connect to the MQTT broker
client = MQTTClient(client_id, broker_ip)
client.connect()

while True:
    # Read temperature data
    temp_data = read_temperature()
    
    # Publish temperature data to "sensors/temp" topic
    client.publish(b'sensors/temp', str(temp_data).encode())
    
    # Wait for 5 seconds before the next reading
    time.sleep(5)